import {
  connectTooltip,
  tooltipManager,
  type TooltipConnector,
} from '@o9ds/core';

export interface O9IconButtonLinkOptions {
  variant?: 'primary' | 'secondary' | 'tertiary' | 'outline' | 'danger';
  size?: 'xs' | 'sm' | 'md' | 'lg';
  icon?: string;
  href?: string;
  target?: string;
  tooltip?: string;
  isDisabled?: boolean;
  isLoading?: boolean;
  onClick?: (event: Event) => void;
}

type RequiredIconButtonLinkOptions = Required<Omit<O9IconButtonLinkOptions, 'onClick' | 'target'>> & {
  target: string | null;
  onClick: ((event: Event) => void) | null;
};

export class O9IconButtonLink {
  private _element: HTMLAnchorElement | null;
  private _options: RequiredIconButtonLinkOptions;
  private _iconEl: HTMLSpanElement | null = null;
  private _originalHref: string;
  private _tooltipConnector: TooltipConnector | null = null;
  private _boundHandleClick: (event: Event) => void;

  static readonly VARIANTS = ['primary', 'secondary', 'tertiary', 'outline', 'danger'] as const;
  static readonly SIZES = ['xs', 'sm', 'md', 'lg'] as const;

  static readonly DEFAULTS: RequiredIconButtonLinkOptions = {
    variant: 'primary',
    size: 'md',
    icon: '',
    href: '',
    target: null,
    tooltip: '',
    isDisabled: false,
    isLoading: false,
    onClick: null,
  };

  static initialize(element: HTMLAnchorElement, options?: O9IconButtonLinkOptions): O9IconButtonLink {
    return new O9IconButtonLink(element, options);
  }

  constructor(element: HTMLAnchorElement, options?: O9IconButtonLinkOptions) {
    this._element = element;
    this._originalHref = element.getAttribute('href') ?? '';

    const variant = options?.variant && (O9IconButtonLink.VARIANTS as readonly string[]).includes(options.variant)
      ? options.variant
      : O9IconButtonLink.DEFAULTS.variant;

    const size = options?.size && (O9IconButtonLink.SIZES as readonly string[]).includes(options.size)
      ? options.size
      : O9IconButtonLink.DEFAULTS.size;

    this._options = {
      ...O9IconButtonLink.DEFAULTS,
      ...options,
      variant,
      size,
      icon: options?.icon ?? O9IconButtonLink.DEFAULTS.icon,
      href: options?.href ?? this._originalHref,
      target: options?.target ?? null,
      tooltip: options?.tooltip ?? O9IconButtonLink.DEFAULTS.tooltip,
      onClick: options?.onClick ?? null,
    };

    this._boundHandleClick = this._handleClick.bind(this);

    this._render();
    this._bindEvents();
    this._connectTooltip();
  }

  private _connectTooltip(): void {
    if (!this._element || !this._options.tooltip) return;
    this._tooltipConnector = connectTooltip(tooltipManager, {
      anchor: this._element,
      content: this._options.tooltip,
    });
  }

  private _render(): void {
    const el = this._element;
    if (!el) return;

    el.textContent = '';

    el.classList.add('o9ds-icon-btn');
    el.classList.add(`o9ds-btn--${this._options.variant}`);
    el.classList.add(`o9ds-btn--${this._options.size}`);

    if (this._options.icon) {
      this._iconEl = this._createIconEl(this._options.icon);
      el.appendChild(this._iconEl);
    }

    if (this._options.tooltip) {
      el.setAttribute('aria-label', this._options.tooltip);
    }

    this._applyHref();
    this._applyTarget();

    if (this._options.isDisabled) {
      this._applyDisabled(true);
    }

    if (this._options.isLoading) {
      el.classList.add('loading');
      el.setAttribute('aria-busy', 'true');
    }
  }

  private _createIconEl(iconName: string): HTMLSpanElement {
    const span = document.createElement('span');
    span.className = `o9ds-btn__ico o9con o9con-${iconName}`;
    span.setAttribute('aria-hidden', 'true');
    return span;
  }

  private _applyHref(): void {
    const el = this._element;
    if (!el) return;

    if (this._options.isDisabled) {
      el.removeAttribute('href');
    } else {
      el.setAttribute('href', this._options.href);
    }
  }

  private _applyTarget(): void {
    const el = this._element;
    if (!el || this._options.isDisabled) return;

    if (this._options.target) {
      el.setAttribute('target', this._options.target);
      if (this._options.target === '_blank') {
        el.setAttribute('rel', 'noopener noreferrer');
      }
    } else {
      el.removeAttribute('target');
      el.removeAttribute('rel');
    }
  }

  private _applyDisabled(state: boolean): void {
    const el = this._element;
    if (!el) return;

    if (state) {
      el.classList.add('is-disabled');
      el.setAttribute('aria-disabled', 'true');
      el.removeAttribute('href');
      el.removeAttribute('target');
      el.removeAttribute('rel');
      el.setAttribute('tabindex', '0');
    } else {
      el.classList.remove('is-disabled');
      el.removeAttribute('aria-disabled');
      el.removeAttribute('tabindex');
      this._applyHref();
      this._applyTarget();
    }
  }

  private _bindEvents(): void {
    this._element?.addEventListener('click', this._boundHandleClick);
  }

  private _handleClick(event: Event): void {
    if (this._options.isDisabled || this._options.isLoading) {
      event.preventDefault();
      event.stopPropagation();
      return;
    }

    this._dispatchEvent('ico-btn-lnk:click', {
      href: this._options.href,
    });

    if (this._options.onClick) {
      this._options.onClick(event);
    }
  }

  private _dispatchEvent(name: string, detail: Record<string, unknown>): void {
    this._element?.dispatchEvent(new CustomEvent(name, {
      bubbles: true,
      cancelable: true,
      detail,
    }));
  }

  setIcon(iconName: string): void {
    if (!iconName) return;

    if (this._iconEl) {
      const oldClass = this._options.icon ? `o9con-${this._options.icon}` : null;
      if (oldClass) {
        this._iconEl.classList.remove(oldClass);
      }
      this._iconEl.classList.add(`o9con-${iconName}`);
    } else if (this._element) {
      this._iconEl = this._createIconEl(iconName);
      this._element.insertBefore(this._iconEl, this._element.firstChild);
    }

    this._options.icon = iconName;
  }

  setHref(href: string): void {
    this._options.href = href;
    this._applyHref();
  }

  setTooltip(tooltip: string): void {
    this._options.tooltip = tooltip;
    this._element?.setAttribute('aria-label', tooltip);
    this._tooltipConnector?.update({ content: tooltip });
  }

  setLoading(isLoading: boolean): void {
    this._options.isLoading = isLoading;

    if (isLoading) {
      this._element?.classList.add('loading');
      this._element?.setAttribute('aria-busy', 'true');
    } else {
      this._element?.classList.remove('loading');
      this._element?.removeAttribute('aria-busy');
    }
  }

  disabled(state?: boolean): boolean | void {
    if (state === undefined) {
      return this._options.isDisabled;
    }

    this._options.isDisabled = state;
    this._applyDisabled(state);
  }

  focus(): void {
    if (this._element && !this._options.isLoading) {
      this._element.focus();
    }
  }

  destroy(): void {
    const el = this._element;
    if (!el) return;

    el.removeEventListener('click', this._boundHandleClick);

    el.classList.remove('o9ds-icon-btn', 'is-disabled', 'loading');
    O9IconButtonLink.VARIANTS.forEach(v => el.classList.remove(`o9ds-btn--${v}`));
    O9IconButtonLink.SIZES.forEach(s => el.classList.remove(`o9ds-btn--${s}`));

    el.removeAttribute('aria-label');
    el.removeAttribute('aria-disabled');
    el.removeAttribute('aria-busy');
    el.removeAttribute('tabindex');
    el.removeAttribute('target');
    el.removeAttribute('rel');

    if (this._originalHref) {
      el.setAttribute('href', this._originalHref);
    }

    this._iconEl?.remove();

    this._tooltipConnector?.destroy();
    this._tooltipConnector = null;

    this._element = null;
    this._iconEl = null;
  }
}
